import React, { useState, useRef, useCallback } from "react";
import { projects, PROJECT_CATEGORIES } from "../../data/portfolio";
import { useScrollReveal } from "../../hooks/useScrollReveal";
import ProjectModal from "../ui/ProjectModal";
import "./Projects.css";

// ─── Placeholder visuel ───────────────────────────────────────
const PLACEHOLDER_MAP = {
  robot:      { emoji: "🤖", tech: "Arduino & C++" },
  cv:         { emoji: "📄", tech: "HTML / CSS / JS" },
  game:       { emoji: "🎮", tech: "Python & Pygame" },
  portfolio:  { emoji: "💻", tech: "React" },
  portfolio1: { emoji: "🌐", tech: "HTML / CSS / JS" },
};

function ProjectVisual({ project, accent }) {
  const p = PLACEHOLDER_MAP[project.placeholder] || { emoji: "🗂️", tech: project.tags[0] };
  return (
    <div className="pcard__visual" style={{ "--accent": accent }}>
      <span className="pcard__visual-emoji">{p.emoji}</span>
      <span className="pcard__visual-tech">{p.tech}</span>
      {project.inProgress && <span className="pcard__badge pcard__badge--wip">En cours</span>}
      {project.highlight && <span className="pcard__badge pcard__badge--hl">{project.highlight}</span>}
    </div>
  );
}

// ─── Carrousel ────────────────────────────────────────────────
function Carousel({ items, accent, onCardClick }) {
  const [current, setCurrent] = useState(0);
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef(null);
  const dragDelta = useRef(0);
  const total = items.length;

  const goTo = useCallback((idx) => {
    setCurrent(Math.max(0, Math.min(idx, total - 1)));
  }, [total]);

  // Touch
  const onTouchStart = (e) => { dragStart.current = e.touches[0].clientX; dragDelta.current = 0; };
  const onTouchMove  = (e) => { if (dragStart.current !== null) dragDelta.current = e.touches[0].clientX - dragStart.current; };
  const onTouchEnd   = () => {
    if (Math.abs(dragDelta.current) > 50) dragDelta.current < 0 ? goTo(current + 1) : goTo(current - 1);
    dragStart.current = null; dragDelta.current = 0;
  };

  // Mouse drag
  const onMouseDown  = (e) => { dragStart.current = e.clientX; dragDelta.current = 0; setIsDragging(false); };
  const onMouseMove  = (e) => { if (dragStart.current !== null) { dragDelta.current = e.clientX - dragStart.current; if (Math.abs(dragDelta.current) > 5) setIsDragging(true); } };
  const onMouseUp    = () => {
    if (Math.abs(dragDelta.current) > 50) dragDelta.current < 0 ? goTo(current + 1) : goTo(current - 1);
    dragStart.current = null; dragDelta.current = 0;
    setTimeout(() => setIsDragging(false), 0);
  };
  const onMouseLeave = () => { if (dragStart.current !== null) { dragStart.current = null; dragDelta.current = 0; setIsDragging(false); } };

  // Keyboard
  const onKeyDown = (e) => {
    if (e.key === "ArrowLeft")  { e.preventDefault(); goTo(current - 1); }
    if (e.key === "ArrowRight") { e.preventDefault(); goTo(current + 1); }
  };

  if (total === 0) return null;

  return (
    <div className="carousel" tabIndex={0} onKeyDown={onKeyDown} aria-label="Carrousel de projets">
      {/* Track */}
      <div
        className={`carousel__track-wrap${isDragging ? " carousel__track-wrap--dragging" : ""}`}
        onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd}
        onMouseDown={onMouseDown}   onMouseMove={onMouseMove}  onMouseUp={onMouseUp} onMouseLeave={onMouseLeave}
      >
        <div
          className="carousel__track"
          style={{ transform: `translateX(calc(-${current * 100}% - ${current * 1.5}rem))` }}
        >
          {items.map((project, idx) => (
            <div
              key={project.id}
              className={`pcard${idx === current ? " pcard--active" : ""}`}
              style={{ "--accent": accent }}
              onClick={() => { if (!isDragging) onCardClick(project, accent); }}
              role="button"
              tabIndex={-1}
              aria-label={`Voir le projet ${project.title}`}
            >
              <ProjectVisual project={project} accent={accent} />
              <div className="pcard__body">
                <p className="pcard__subtitle">{project.subtitle}</p>
                <h4 className="pcard__title">{project.title}</h4>
                <p className="pcard__description">{project.description}</p>
                <div className="pcard__tags">
                  {project.tags.map(t => <span key={t} className="pcard__tag">{t}</span>)}
                </div>
              </div>
              <div className="pcard__cta">
                Voir le projet
                <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                  <path d="M7 17L17 7M17 7H7M17 7v10"/>
                </svg>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Contrôles */}
      <div className="carousel__controls">
        <div className="carousel__dots">
          {items.map((_, i) => (
            <button
              key={i}
              className={`carousel__dot${i === current ? " carousel__dot--active" : ""}`}
              style={i === current ? { background: accent, width: "22px" } : {}}
              onClick={() => goTo(i)}
              aria-label={`Projet ${i + 1}`}
            />
          ))}
        </div>
        <div className="carousel__arrows">
          <button className="carousel__arrow" onClick={() => goTo(current - 1)} disabled={current === 0} aria-label="Précédent">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M15 18l-6-6 6-6"/></svg>
          </button>
          <span className="carousel__counter">{current + 1} / {total}</span>
          <button className="carousel__arrow" onClick={() => goTo(current + 1)} disabled={current === total - 1} aria-label="Suivant">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M9 18l6-6-6-6"/></svg>
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Section principale ───────────────────────────────────────
const ALL_TAB = { id: "all", label: "Tous", accent: "#d4a5a5" };

export default function Projects() {
  const [activeTab, setActiveTab] = useState("all");
  const [selected, setSelected]   = useState(null);
  const [selectedAccent, setSelectedAccent] = useState(null);
  const { ref, isVisible } = useScrollReveal();

  // Projets filtrés selon l'onglet actif
  const filtered = activeTab === "all"
    ? projects
    : projects.filter(p => p.category === activeTab);

  // Couleur accent de l'onglet actif
  const activeAccent = activeTab === "all"
    ? ALL_TAB.accent
    : (PROJECT_CATEGORIES.find(c => c.id === activeTab)?.accent ?? "#d4a5a5");

  const tabs = [ALL_TAB, ...PROJECT_CATEGORIES];

  return (
    <section className="section projects" id="projets">
      <div className="container">
        {/* En-tête */}
        <div ref={ref} className={`projects__head${isVisible ? " revealed" : ""}`}>
          <h2 className="section-title">Mes Projets</h2>
          <p className="section-sub">
            Glisse sur mobile · utilise les flèches sur desktop · clique pour en savoir plus.
          </p>
        </div>

        {/* Onglets filtre */}
        <div className="projects__tabs" role="tablist">
          {tabs.map(tab => (
            <button
              key={tab.id}
              role="tab"
              aria-selected={activeTab === tab.id}
              className={`projects__tab${activeTab === tab.id ? " projects__tab--active" : ""}`}
              style={activeTab === tab.id ? { "--tab-accent": tab.accent } : {}}
              onClick={() => setActiveTab(tab.id)}
            >
              {tab.label}
              <span className="projects__tab-count">
                {tab.id === "all" ? projects.length : projects.filter(p => p.category === tab.id).length}
              </span>
            </button>
          ))}
        </div>

        {/* Carrousel */}
        <Carousel
          key={activeTab}           /* remonte à 0 à chaque changement d'onglet */
          items={filtered}
          accent={activeAccent}
          onCardClick={(project, accent) => { setSelected(project); setSelectedAccent(accent); }}
        />
      </div>

      {selected && (
        <ProjectModal
          project={selected}
          accent={selectedAccent}
          onClose={() => { setSelected(null); setSelectedAccent(null); }}
        />
      )}
    </section>
  );
}
